/// Handles deep link routing with authorization checks
class DeepLinkRouter {
  final GlobalKey<NavigatorState> navigatorKey;
  final AuthService _authService;

  DeepLinkRouter({
    required this.navigatorKey,
    AuthService? authService,
  }) : _authService = authService ?? AuthService();

  /// Route a validated deep link to the appropriate screen
  /// Returns true if navigation was successful
  bool route(ValidatedDeepLink deepLink) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('[DeepLink] Navigator not available');
      return false;
    }

    switch (deepLink.host) {
      case 'profile':
        return _routeToProfile(navigator, deepLink);
      case 'payment':
        return _routeToPayment(navigator, deepLink);
      default:
        debugPrint('[DeepLink] No route handler for host: ${deepLink.host}');
        return false;
    }
  }

  bool _routeToProfile(NavigatorState navigator, ValidatedDeepLink deepLink) {
    final profileId = deepLink.parameters['profileId'];
    if (profileId == null) return false;

    // Authorization check: user must be authenticated to view profiles
    if (!_authService.isAuthorizedForProfile(profileId)) {
      debugPrint(
        '[DeepLink] Unauthorized profile access attempt for ID: $profileId',
      );
      // Navigate to login instead, preserving the intended destination
      navigator.pushNamed(
        '/login',
        arguments: {
          'returnRoute': '/profile/$profileId',
          'reason': 'Please log in to view profiles',
        },
      );
      return true;
    }

    final tab = deepLink.parameters['tab'];
    navigator.pushNamed(
      '/profile/$profileId',
      arguments: {
        'profileId': profileId,
        if (tab != null) 'tab': tab,
        'source': deepLink.parameters['ref'] ?? 'deeplink',
      },
    );
    return true;
  }

  bool _routeToPayment(NavigatorState navigator, ValidatedDeepLink deepLink) {
    // Authorization check: payment routes ALWAYS require authentication
    if (!_authService.isAuthorizedForPayment()) {
      debugPrint('[DeepLink] Unauthorized payment access attempt');
      navigator.pushNamed(
        '/login',
        arguments: {
          'returnRoute': '/payment/${deepLink.action}',
          'reason': 'Please log in to access payment features',
        },
      );
      return true;
    }

    switch (deepLink.action) {
      case 'confirm':
        navigator.pushNamed(
          '/payment/confirm',
          arguments: {
            'token': deepLink.parameters['token'],
            'orderId': deepLink.parameters['order_id'],
            'source': deepLink.parameters['ref'] ?? 'deeplink',
          },
        );
        return true;
      case 'cancel':
        navigator.pushNamed(
          '/payment/cancel',
          arguments: {
            'orderId': deepLink.parameters['order_id'],
          },
        );
        return true;
      case 'status':
        navigator.pushNamed(
          '/payment/status',
          arguments: {
            'orderId': deepLink.parameters['order_id'],
          },
        );
        return true;
      default:
        return false;
    }
  }
}

/// Main deep link handler that integrates with uni_links
class DeepLinkHandler {
  StreamSubscription? _linkSubscription;
  final DeepLinkRouter _router;

  DeepLinkHandler({required DeepLinkRouter router}) : _router = router;

  /// Initialize deep link handling (call in app startup)
  Future<void> initialize() async {
    // Handle the initial link that launched the app
    await _handleInitialLink();

    // Listen for subsequent links while app is running
    _linkSubscription = uriLinkStream.listen(
      _handleIncomingUri,
      onError: (error) {
        debugPrint('[DeepLink] Stream error: $error');
      },
    );
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        _handleIncomingUri(initialUri);
      }
    } catch (e) {
      debugPrint('[DeepLink] Error getting initial link: $e');
    }
  }

  void _handleIncomingUri(Uri? uri) {
    if (uri == null) return;

    debugPrint('[DeepLink] Received URI: $uri');

    // Step 1: Validate the deep link
    final validationResult = DeepLinkValidator.validate(uri);

    if (!validationResult.isValid) {
      debugPrint(
        '[DeepLink] Validation failed: ${validationResult.errorMessage}',
      );
      // Optionally log to analytics for monitoring suspicious activity
      _logSuspiciousLink(uri, validationResult.errorMessage ?? 'Unknown');
      return;
    }

    // Step 2: Route the validated deep link (includes authorization checks)
    final deepLink = validationResult.deepLink!;
    debugPrint('[DeepLink] Validated: $deepLink');

    final routed = _router.route(deepLink);
    if (!routed) {
      debugPrint('[DeepLink] Failed to route: $deepLink');
    }
  }

  void _logSuspiciousLink(Uri uri, String reason) {
    // In production, send to your analytics/security monitoring service
    debugPrint(
      '[DeepLink][SECURITY] Suspicious link rejected: $uri | Reason: $reason',
    );
  }

  void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
  }
}

