  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      navigatorKey: _navigatorKey,
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      initialRoute: '/',
      onGenerateRoute: _generateRoute,
    );
  }

  Route<dynamic>? _generateRoute(RouteSettings settings) {
    final uri = Uri.parse(settings.name ?? '/');
    final args = settings.arguments as Map<String, dynamic>? ?? {};

    // Profile routes: /profile/{id}
    if (uri.pathSegments.isNotEmpty && uri.pathSegments.first == 'profile') {
      final profileId =
          uri.pathSegments.length > 1 ? uri.pathSegments[1] : null;
      return MaterialPageRoute(
        builder: (_) => ProfileScreen(
          profileId: profileId ?? args['profileId'] ?? 'unknown',
          tab: args['tab'],
          source: args['source'] ?? 'direct',
        ),
        settings: settings,
      );
    }

    // Payment routes: /payment/{action}
    if (uri.pathSegments.isNotEmpty && uri.pathSegments.first == 'payment') {
      final action =
          uri.pathSegments.length > 1 ? uri.pathSegments[1] : 'unknown';
      return MaterialPageRoute(
        builder: (_) => PaymentScreen(
          action: action,
          token: args['token'],
          orderId: args['orderId'],
          source: args['source'] ?? 'direct',
        ),
        settings: settings,
      );
    }

    // Login route
    if (settings.name == '/login') {
      return MaterialPageRoute(
        builder: (_) => LoginScreen(
          returnRoute: args['returnRoute'],
          reason: args['reason'],
        ),
        settings: settings,
      );
    }

    // Default home route
    return MaterialPageRoute(
      builder: (_) => const HomeScreen(),
      settings: settings,
    );
  }
}

